<!DOCTYPE html>
<html lang="en">

<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Document</title>

    <style>
        .teks-1 {
            color: aqua;
        }

        .teks-2 {
            color: bisque;
        }

        .container {
            background: blue;
            width: 100vw;
            display: flex;
            flex-direction: row;
            justify-content: space-around;
            color: white;
        }

        .container-2 {
            width: 100vw;
            height: 100vh;
            /* background: gray; */
            display: flex;
            flex-direction: row;
            /* justify-content: center;
            align-items:center; */
            gap: 1rem;
        }

        .sub-container {
            background: black;
            width: 25vw;
            height: 80vh;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
margin-top:1rem;
        }

        .gambar {
            width: 20rem;
            height: 15rem;
        }

        .judul {
            color: white;
            font-weight: bold;
            font-size: 1.2rem;
        }

        .deskripsi {
            color: white;
        }
    </style>
</head>

<body>
    <p class="teks-1">Web <span class="teks-2">Saya</span></p>
    <div class="container">
        <p class="beranda">Beranda</p>
        <p class="kontak">Kontak saya</p>
        <p class="tentang">Tentang saya</p>
    </div>

    <div class="container-2">
        <div class="sub-container">
            <img class="gambar" src="data:image/jpeg;base64," alt="">
            <p class="judul">Nasi Goreng</p>
            <p class="deskripsi">Nasi goreng enak</p>
        </div>
        <div class="sub-container">
            <img class="gambar" src="data:image/jpeg;base64," alt="">
            <p class="judul">Rendang</p>
            <p class="deskripsi">Rendang pak bryan</p>
        </div>
        <div class="sub-container">
            <img class="gambar" src="data:image/jpeg;base64," alt="">
            <p class="judul">Sate</p>
            <p class="deskripsi">Sate pak kartika</p>
        </div>
        <div class="sub-container">
            <img class="gambar" src="data:image/jpeg;base64," alt="">
            <p class="judul">Soto</p>
            <p class="deskripsi">Soto pak alby</p>
        </div>
    </div>
</body>

</html>
